/**
 * Pre-rendered alert chimes (MP3), served from a real URL.
 *
 * iOS Safari refuses to play a `data:` URI as an <audio> source (it rejects with
 * NotSupportedError) and a media element there expects HTTP range support — so the
 * board cannot embed the chimes inline. They live here as base64 (generated to mirror
 * the board's WebAudio tones) so they still ship in the package + image with no binary
 * assets, and both the local server and the relay serve them at /snd/<name>.mp3 with
 * range support.
 */
import type * as http from "http";

// base64 WAV bodies — generated by scripts (mirror the dashboard's WebAudio chimes).
const B64: Record<string, string> = {
  done: "",
  waiting: "",
  error: "",
};

export const SOUNDS: Record<string, Buffer> = Object.fromEntries(
  Object.entries(B64).map(([k, v]) => [k, Buffer.from(v, "base64")]),
);

/** The chime name for a `/snd/<name>.mp3` path, or null if it isn't a known chime. */
export function soundName(pathname: string): string | null {
  const m = /^\/snd\/([a-z]+)\.mp3$/.exec(pathname);
  return m && SOUNDS[m[1]] ? m[1] : null;
}

/** Serve a chime buffer as audio/mpeg with HTTP range support (iOS <audio> needs it). */
export function serveSound(req: http.IncomingMessage, res: http.ServerResponse, buf: Buffer): void {
  const total = buf.length;
  const base: Record<string, string | number> = {
    "Content-Type": "audio/mpeg",
    "Accept-Ranges": "bytes",
    "Cache-Control": "public, max-age=86400",
    "X-Content-Type-Options": "nosniff",
  };
  const range = req.headers.range;
  if (range) {
    const m = /bytes=(\d*)-(\d*)/.exec(range);
    let start = m && m[1] ? parseInt(m[1], 10) : 0;
    let end = m && m[2] ? parseInt(m[2], 10) : total - 1;
    if (!Number.isFinite(start) || start < 0) start = 0;
    if (!Number.isFinite(end) || end >= total) end = total - 1;
    if (start > end) {
      res.writeHead(416, { ...base, "Content-Range": `bytes */${total}` });
      res.end();
      return;
    }
    const slice = buf.subarray(start, end + 1);
    res.writeHead(206, { ...base, "Content-Range": `bytes ${start}-${end}/${total}`, "Content-Length": slice.length });
    return void res.end(req.method === "HEAD" ? undefined : slice);
  }
  res.writeHead(200, { ...base, "Content-Length": total });
  res.end(req.method === "HEAD" ? undefined : buf);
}
